import React, { Component } from 'react'
import logo from '../../assets/images/logo1.png'
import { Link } from "react-router-dom";
import Axios from '../../Config/Axios';
import { authHeaders, toasterAlert, setSession, isAuthenticated, getToken, destroySession } from "../../Helpers/Functions";
import Redirect from "../../Utils/history";
import GoogleLogin from 'react-google-login';
import userAuthenicated from '../../Services/auth.service'
import Gpic from "../../assets/images/gPic.png";
import Header from "../../Components/Layouts/AuthLayout/Header";

class Login extends Component {
    state = {
        email: '', password: '', loading: false, errors: {
            email: '',
            password: ''
        }
    };

    componentDidMount() {
        if (isAuthenticated()) {
            Redirect.push(`/`);
        }
    }
    onChangeState = (event) => {
        const { name, value } = event.target;
        this.setState({ [name]: value })
        console.log('name', this.state.email);

    }
    responseGoogle = (response) => {
        console.log(response);
        // Google Access Token
        if(response.accessToken !== undefined){
            Axios.get('/callback?authToken=' + response.accessToken).then(response => {
                // console.log('Google signin --- '+ JSON.stringify(response));
                // Authenticated Service
                userAuthenicated.userAuthResponseHandler(response);
            }).catch(error => {
                console.log(error, 'error data')
                // if(!error.response.data.errors?.outcome_id )
    
                toasterAlert('error', 'Authentication Failed!')
                //
                // return error.response
            }).finally(() => {
                this.setState({ loading: false });
            });
        }
    }
    login = () => {
        const { email, password } = this.state;
        let { emailError, passwordError } = '';

        if (!email) {
            emailError = "Email is required";
        }

        if (!password) {
            passwordError = "Password is required";
        }

        this.setState({
            errors: {
                email: emailError,
                password: passwordError
            }
        })
        if (emailError || passwordError) {
            return true;
        }
        this.setState({ loading: true });
        Axios.post(`/login`, { email, password }).then(response => {
            // Authenticated Service
            localStorage.setItem('RegisterEmail', response.data.user[0].email);
            // console.log('ddddd ' + JSON.stringify(response));
            userAuthenicated.userAuthResponseHandler(response);
        }).catch(error => {
            console.log(error.response, 'error data')
            // if(!error.response.data.errors?.outcome_id )
            if(error.response && error.response.status === 401){
                toasterAlert('error', "Email or Password doesn't match.")
            }

            //
            // return error.response
        }).finally(() => {
            this.setState({ loading: false });
        });

        // Axios.post('https://reqres.in/api/articles', {email,password} )
        //     .then(response => console.log(response));
    }

    // forgetPassord(){
    //     Redirect.push('/forgetPassword')
    // }
    render() {

        return (
            <>
                <div className="container-fluid login-wrapper">
                <Header />
                    <div className="row mar-width-0 width-wrap pt-5">
                        {/* <div className="col-md-12 text-center pt-2">
                            <Link to="/"> <img src={logo} alt="" /></Link>
                        </div> */}
                        <div className="col-md-12 login-heading">
                            <p className="font-family">Make the most of your professional life</p>
                        </div>

                        <div className="row mar-width-0 form-bg">
                            <div className="col-md-12 p-0">
                                <h3 className="font-family lo-title">Login</h3>
                            </div>
                            <div className="col-md-12 form-wrap p-0">
                                <form className="w-100">

                                    <div className="form-group d-none">
                                        <label htmlFor="exampleInputEmail11">Account type</label>
                                        <div className="wrapper">
                                            <input type="radio" name="select" id="option-1" checked />
                                            <input type="radio" name="select" id="option-2" />
                                            <label htmlFor="option-1" className="option option-1">
                                                <span>Mentee</span>
                                            </label>
                                            <label htmlFor="option-2" className="option option-2">
                                                <span>Mentor</span>
                                            </label>
                                        </div>
                                    </div>

                                    <div className="form-group">
                                        <label htmlFor="exampleInputEmail1">Email</label>
                                        <input type="email" name="email" onChange={this.onChangeState} value={this.state.email} className="form-control" id="exampleInputEmail1"
                                        />
                                        <span className="error">{this.state.errors.email}</span>
                                    </div>

                                    <div className="form-group">
                                        <label htmlFor="passwordInput">Password</label>
                                        <input type="password" name="password" onChange={this.onChangeState} value={this.state.password} className="form-control" id="passwordInput" />
                                        <span className="error">{this.state.errors.password}</span>
                                        <div className="text-end">
                                            <Link to="/forgetPassword"><span>Forget Password?</span></Link>
                                        </div>
                                    </div>
                                    <button type="button" disabled={this.state.loading} onClick={this.login} className="btn btn-primary btnLogin">Login</button>
                                </form>
                            </div>
                            <div className="col-md-12 or-wrap">
                                <h2 className="h2_2"><span>or</span></h2>
                            </div>
                            <div className="col-md-12">
                                <GoogleLogin
                                    clientId="340365300393-1ma31t11b7akqn61tsbpt8h0g9e134a7.apps.googleusercontent.com"
                                    render={renderProps => (
                                        <button onClick={renderProps.onClick} disabled={renderProps.disabled} className="btn btn-primary btnGoogle"><img className="gpic" src={Gpic} alt="" /> Login with Google</button>
                                    )}
                                    buttonText="Login"
                                    buttonText="Login"
                                    onSuccess={this.responseGoogle}
                                    onFailure={this.responseGoogle}
                                    cookiePolicy={'single_host_origin'}
                                />

                            </div>
                            <div className="col-md-12 bottom-wrap2">
                                <span>Don't have an account yet?</span> &nbsp;
                                <Link to="/signup" className="">Sign Up</Link>

                            </div>
                        </div>



                    </div>
                </div>
            </>
        )
    }
}

export default Login
